bounce_count.dax:
EVALUATE
ROW(
  "Bounce Count",
  CALCULATE(
    DISTINCTCOUNT(Table[Cust ID]),
    Table[Bounce status] IN {"Tech", "Non Tech"}
  )
)

bounce_percent.dax:
EVALUATE
ROW(
  "Bounce %",
  DIVIDE(
    CALCULATE(
      DISTINCTCOUNT(Table[Cust ID]),
      Table[Bounce status] IN {"Tech", "Non Tech"}
    ),
    DISTINCTCOUNT(Table[Cust ID])
  ) * 100
)

bounce_by_region.dax:
EVALUATE
SUMMARIZECOLUMNS(
  Table[Region],
  "Bounce Count", CALCULATE(
    DISTINCTCOUNT(Table[Cust ID]),
    Table[Bounce status] IN {"Tech", "Non Tech"}
  ),
  "Bounce %", DIVIDE(
    CALCULATE(DISTINCTCOUNT(Table[Cust ID]), Table[Bounce status] IN {"Tech", "Non Tech"}),
    DISTINCTCOUNT(Table[Cust ID])
  ) * 100
)
